import { Component, OnInit } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { FirebaseService } from '../../shared/firebase.service';
import { Router } from '@angular/router';

@Component({
  selector: 'app-cadastro',
  templateUrl: './cadastro.component.html',
  styleUrls: ['./cadastro.component.css']
})
export class CadastroComponent implements OnInit {


  formulario: FormGroup;
  flag = false;

  constructor(public formBuild: FormBuilder, public service: FirebaseService, public router: Router) { }

  ngOnInit() {

    this.formulario = this.formBuild.group({
      email: [null, [Validators.required, Validators.email]],
      senha: [null, [Validators.required]]
    });
  }

  acessar() {
    console.log(this.formulario.value);
    if (!this.formulario.valid) {
      this.validacao(this.formulario);
      this.flag = true;
    } else {

      const email = this.formulario.get('email').value;
      const senha = this.formulario.get('senha').value;

      this.service.createLoginWithEmaPassword(email, senha).then(data => {
        console.log(data);
        this.router.navigate(['/sisnutri']);
      }).catch(e => {
        console.log(e);
      });
    }
  }

  validTouched(valor: string) {
    return !this.formulario.get(valor).valid && (this.formulario.get(valor).touched && this.formulario.get(valor).markAsDirty);
  }


  validacao(form: FormGroup) {
    Object.keys(form.controls).forEach(data => {
      const valor = form.get(data);
      valor.markAsDirty();
      valor.markAsTouched();
    }, e => {
      console.log(e);
    });
  }

}
