import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';
import { HomeComponent } from './component/home/home.component';
import { AssessoriaFinanceiraComponent } from './component/assessoria-financeira/assessoria-financeira.component';
import { NutricaoComponent } from './component/nutricao/nutricao.component';
import { CargaComponent } from './component/carga/carga.component';
import { EtiquetagemComponent } from './component/etiquetagem/etiquetagem.component';
import { FormNutricaoComponent } from './component/form-nutricao/form-nutricao.component';
import { AcessoComponent } from './component/acesso/acesso.component';

const routes: Routes = [
  {path: '', component: HomeComponent},
  {path: 'assessoria', component: AssessoriaFinanceiraComponent},
  {path: 'nutricao', component: NutricaoComponent},
  {path: 'carga', component: CargaComponent},
  {path: 'etiquetagem', component: EtiquetagemComponent},
  {path: 'sisnutri', component: FormNutricaoComponent},
  {path: 'acesso', component: AcessoComponent},
  {path: '', pathMatch: 'full', redirectTo: ''}
];

@NgModule({
  imports: [RouterModule.forRoot(routes)],
  exports: [RouterModule]
})
export class AppRoutingModule { }
