import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';
import { AngularFireAuth } from 'angularfire2/auth';
import { FirebaseService } from '../../shared/firebase.service';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';


@Component({
  selector: 'app-acesso',
  templateUrl: './acesso.component.html',
  styleUrls: ['./acesso.component.css']
})
export class AcessoComponent implements OnInit {

  public authEmail: string;
  public formulario: FormGroup;

  constructor(
    public router: Router,
    public auth: AngularFireAuth,
    public service: FirebaseService,
    public formBuider: FormBuilder) { }

  ngOnInit() {

    this.formulario = this.formBuider.group({
      email: [null, [Validators.email, Validators.required]],
      senha: [null, [Validators.required]]
    });
  }


  google() {

    this.service.logINGoogle().then((res) => {
        this.router.navigate(['/sisnutri']);
    }).catch(erro => {
      console.log(erro);
    });
    this.router.navigate(['/sisnutri']);
  }


  facebook() {
    this.service.logINFace().then(data => {
      console.log(data);
      this.router.navigate(['/sisnutri']);
    }).catch(e => {
      alert('Facebook não conectado ...');
    });
  }

  enviar() {
    if (!this.formulario.valid) {
      this.verificando(this.formulario);
    } else {
      console.log(this.formulario.value);
      const email = this.formulario.get('email').value;
      const senha = this.formulario.get('senha').value;

      this.service
        .loginWithEmailPassword(email, senha)
        .then(data => {
          console.log(data);
          this.router.navigate(['/sisnutri']);
        })
        .catch(e => {
          console.log(e);
        });
    }
  }

  verificando(form: FormGroup) {
    Object.keys(form.controls).forEach(data => {
      console.log(data);
      const valor = form.get(data);
      valor.markAsDirty();
      valor.markAsPending();
      valor.markAsTouched();
    });
  }

  validTouched(valor: string) {
    return (
      !this.formulario.get(valor).valid &&
      (this.formulario.get(valor).touched &&
        this.formulario.get(valor).markAsDirty)
    );
  }

}
