import { Component, OnInit } from '@angular/core';
import { FormGroup, FormBuilder, Validators } from '@angular/forms';
import { Router } from '@angular/router';

import { FirebaseService } from '../../shared/firebase.service';
import { AngularFireAuth } from 'angularfire2/auth';


@Component({
  selector: 'app-form-nutricao',
  templateUrl: './form-nutricao.component.html',
  styleUrls: ['./form-nutricao.component.css']
})
export class FormNutricaoComponent implements OnInit {

  formulario: FormGroup;
  periodos: any[];

  constructor(
    private formBuilder: FormBuilder,
    private service: FirebaseService,
    private router: Router,
    private auth: AngularFireAuth
  ) { }

  formSubmited() {
    console.log(this.formulario.value);
   this.service.save(this.formulario.value).then(() => {
    alert('Ola ' + this.auth.auth.currentUser.displayName + 'Agradecemos suas informações');
     this.sair();
   }, e => {
     alert('Good Bye ' + this.auth.auth.currentUser.displayName );
   });
  }

  ngOnInit() {
    this.periodos = this.service.getPeriodo();
    this.formulario = this.formBuilder.group({
      nome: [null, [Validators.required]],
      dataNascimento: [null, [Validators.required]],
      altura: [null, [Validators.required]],
      peso: [null, [Validators.required]],
      escola: [null, [Validators.required]],
      escolaridade: [null, [Validators.required]],
      periodo: [null, [Validators.required]],
      email: [null, [Validators.required, Validators.email]],
      telefone: [null, [Validators.required]],
      celular: [null, [Validators.required]],
      info: [null, [Validators.required]]
    });
  }

  logout() {
    this.service.logOUTGoogle().then(data => {
      this.router.navigate(['/']);
    }).catch(e => {
      alert('Conflito');
    });
  }


  validTouched(campo) {
    return (
      !this.formulario.get(campo).valid &&
      (this.formulario.get(campo).touched ||
        this.formulario.get(campo).markAsDirty())
    );
  }

  sair() {
    this.service.logOUTGoogle();
    this.router.navigate(['/']);
  }

  clear() {
    this.formulario.reset();
  }

}
