import { Injectable } from '@angular/core';

import { AngularFireAuth } from 'angularfire2/auth';
import { auth } from 'firebase';
import { HttpClient, HttpHeaders } from '@angular/common/http';
import { Form } from '../component/form-nutricao/form';
import { AngularFireDatabase, AngularFireList } from 'angularfire2/database';

@Injectable({
  providedIn: 'root'
})
export class FirebaseService {

  private dbList: AngularFireList<any>;
  private formulario: Form = new Form();

  private httpHeader = {
    headers: new HttpHeaders(
      {'Content-Type': 'application/json'}
    )};

  constructor(
    public fire: AngularFireAuth,
    public http: HttpClient,
    public db: AngularFireDatabase
  ) { }



  save(form: Form) {
    return this.db.list('treel').push({
      nome: form.nome,
      dataNascimento: form.dataNascimento,
      altura: form.altura,
      peso: form.peso,
      escola: form.escola,
      escolaridade: form.escolaridade,
      periodo: form.periodo,
      email: form.email,
      telefone: form.telefone,
      celular: form.celular,
      info: form.info
    });
  }


  logINGoogle() {
    return this.fire.auth.signInWithPopup(new auth.GoogleAuthProvider()).then(data => {
    }).catch(erro => {
      console.log(erro);
    });
  }

  logINFace() {
    return this.fire.auth.signInWithPopup(new auth.FacebookAuthProvider());
  }

  logOUTGoogle() {
    return this.fire.auth.signOut();
  }

  loginWithEmailPassword(email, senha) {
    return this.fire.auth.signInWithEmailAndPassword(email, senha);
  }

  createLoginWithEmaPassword(email, senha) {
    return this.fire.auth.createUserWithEmailAndPassword(email, senha);
  }

  getPeriodo() {
    return [
      { nome: 'Manhã'},
      { nome: 'Tarde'},
      { nome: 'Integral'}
    ];
  }

}
